    }

    public async Task<BenchmarkResult> RunAsync(BenchmarkContext context, CancellationToken ct = default)
    {
        var key = GenerateKey(context);

        // Resume if already completed
        if (_results.TryGetValue(key, out var cached) && cached.IsComplete)
            return cached;

        var result = new BenchmarkResult(context, _baseLogPath);
        _results[key] = result;

        await _dockerSemaphore.WaitAsync(ct);
        try
        {
            result.Start();
            await RunDockerBenchmarkAsync(context, result, ct);
            result.Complete();
        }
        catch (OperationCanceledException)
        {
            result.Cancel();
            throw;
        }
        catch (Exception ex)
        {
            result.Fail(ex);
            throw;
        }
        finally
        {
            _dockerSemaphore.Release();
        }

        SaveResult(key, result);
        return result;
    }

